#include <iostream>

int main() {
    int n{};
    std::cin >> n;

    // BUG: the condition below uses = (assignment) instead of == (comparison).
    // Because 'remainder' is an lvalue, 'remainder = 0' compiles silently
    // but always evaluates to 0 (false), so it always takes the else branch.
    // Fix the condition AND add the missing else branch.
    int remainder = n % 2;
    if (remainder = 0) {
        std::cout << "Even\n";
    }

    return 0;
}

exercises.solution_code:
#include <iostream>

int main() {
    int n{};
    std::cin >> n;

    int remainder = n % 2;
    if (remainder == 0) {
        std::cout << "Even\n";
    } else {
        std::cout << "Odd\n";
    }

    return 0;
}

