#include <iostream>

int main() {
    int a{}, b{};
    std::cin >> a >> b;

    // TODO: fix dangling-else and missing-braces bugs below.
    // The else on line 13 attaches to the inner if, not the outer one.
    // The last std::cout always executes — it is not inside any if.
    if (a > 0)
        if (b > 0)
            std::cout << "both positive\n";
    else                          // dangling: belongs to inner if
        std::cout << "a not positive\n";
        std::cout << "a positive, b not\n";  // always runs — missing braces

    return 0;
}

exercises.solution_code:
#include <iostream>

int main() {
    int a{}, b{};
    std::cin >> a >> b;

    if (a > 0) {
        if (b > 0) {
            std::cout << "both positive\n";
        } else {
            std::cout << "a positive, b not\n";
        }
    } else {
        std::cout << "a not positive\n";
    }

    return 0;
}
